            const pageHeight = doc.internal.pageSize.height;

            // ===== PAGE 1: Assessment Questions =====
            
            // Add logos
            try {
                doc.addImage(LMP_LOGO_BASE64, 'JPEG', 10, 5, 35, 15);
                doc.addImage(VF_LOGO_BASE64, 'WEBP', pageWidth - 45, 5, 35, 15);
                yPos = 25;
            } catch (error) {
                console.error('Error loading logos:', error);
            }

            // Title
            doc.setFillColor(216, 67, 21);
